  public String toString() { return "int"; }
}

/** The bool type. */
class BoolType implements Type {
  public static final BoolType ONLY = new BoolType();
  private BoolType() {}
  public boolean equals(Object o) { return o instanceof BoolType; }
  public int hashCode() { return 2; }
  public String toString() { return "bool"; }
}

/** The unit type (returned by assignment). */
class UnitType implements Type {
  public static final UnitType ONLY = new UnitType();
  private UnitType() {}
  public boolean equals(Object o) { return o instanceof UnitType; }
  public int hashCode() { return 3; }
  public String toString() { return "unit"; }
}

/** The list type: list T. */
class ListType implements Type {
  private Type elemType;
  ListType(Type e) { elemType = e; }
  public Type elemType() { return elemType; }
  public boolean equals(Object o) {
    return (o instanceof ListType) && elemType.equals(((ListType) o).elemType);
  }
  public int hashCode() { return 4 + elemType.hashCode(); }
  public String toString() { return "list " + elemType; }
}

/** The ref type: ref T. */
class RefType implements Type {
  private Type elemType;
  RefType(Type e) { elemType = e; }
  public Type elemType() { return elemType; }
  public boolean equals(Object o) {
    return (o instanceof RefType) && elemType.equals(((RefType) o).elemType);
  }
  public int hashCode() { return 5 + elemType.hashCode(); }
  public String toString() { return "ref " + elemType; }
}

/** The function type: (T1, T2, ... -> Tr). */
class FunType implements Type {
  private Type[] paramTypes;
  private Type returnType;
  FunType(Type[] p, Type r) { paramTypes = p; returnType = r; }
  public Type[] paramTypes() { return paramTypes; }
  public Type returnType() { return returnType; }
  public boolean equals(Object o) {
    if (!(o instanceof FunType)) return false;
    FunType ft = (FunType) o;
    if (paramTypes.length != ft.paramTypes.length) return false;
    for (int i = 0; i < paramTypes.length; i++) {
      if (!paramTypes[i].equals(ft.paramTypes[i])) return false;
    }
    return returnType.equals(ft.returnType);
  }
  public int hashCode() {
    int h = returnType.hashCode();
    for (Type t : paramTypes) h += t.hashCode();
    return h;
  }
  public String toString() {
    StringBuilder sb = new StringBuilder("(");
    for (int i = 0; i < paramTypes.length; i++) {
      if (i > 0) sb.append(", ");
      sb.append(paramTypes[i]);
    }
    sb.append(" -> ").append(returnType).append(")");
    return sb.toString();
  }
}

/** A typed empty constant: empty : Type. The type is the element type of the list. */
class TypedEmpty implements Constant {
  private Type type;
  TypedEmpty(Type t) { type = t; }
  public Type type() { return type; }
  public <T> T accept(ASTVisitor<T> v) { return v.forEmptyConstant(EmptyConstant.ONLY); }
  public String toString() { return "empty : " + type; }
}

/** Parser for Typed Jam (Assignment 5) */

import java.io.*;
import java.util.*;

/** Class that represented parsing errors. */
class ParseException extends RuntimeException {
  ParseException(String s) { super(s); }
  ParseException(Throwable t) { super(t); }
}

/** Token class for the colon separator in type annotations. */
class Colon implements Token {
  public static final Colon ONLY = new Colon();
  private Colon() {}
  public String toString() { return ":"; }
}

/** Token class for type keywords (int, bool, unit, list). */
class TypeToken implements Token {
  private String name;
  TypeToken(String n) { name = n; }
  public String name() { return name; }
  public String toString() { return name; }
}

/** Extended Lexer that handles ':' as a Colon token and adds type keywords. */
class TypedLexer extends Lexer {
  static final TypeToken INT_TYPE = new TypeToken("int");
  static final TypeToken BOOL_TYPE = new TypeToken("bool");
  static final TypeToken UNIT_TYPE = new TypeToken("unit");
  static final TypeToken LIST_TYPE = new TypeToken("list");

  TypedLexer(Reader inputStream) {
    super(inputStream);
    wordTable.put("int", INT_TYPE);
    wordTable.put("bool", BOOL_TYPE);
    wordTable.put("unit", UNIT_TYPE);
    wordTable.put("list", LIST_TYPE);
  }

  @Override
  public Token readToken() {
    try {
      return super.readToken();
    } catch (ParseException e) {
      String msg = e.getMessage();
      if (msg != null && msg.contains("':' is not a legal token")) {
        return Colon.ONLY;
      }
      throw e;
    }
  }
}

class Parser {

  private Lexer in;

  Parser(Lexer i) { in = i; initParser(); }

  Parser(Reader inputStream) { this(new TypedLexer(inputStream)); }

  Parser(String fileName) throws IOException { this(new FileReader(fileName)); }

  Lexer lexer() { return in; }

  public void initParser() { }

  /** Parses the program in the Lexer associated with this. */
  public AST parse() throws ParseException {
    try {
      in.reset();
      AST prog = parseExp();
      Token t = in.readToken();
      if (t == EndOfFile.ONLY) return prog;
      else throw new ParseException("Legal program followed by extra token " + t);
    }
    finally {
      try { in.rdr.close(); }
      catch (IOException e) { throw new ParseException(e); }
    }
  }

  /** Parses and syntactically checks the program in the Lexer associated with this. */
  public AST parseAndCheck() throws ParseException {
    AST prog = parseExp();
    Token t = in.readToken();
    if (t != EndOfFile.ONLY) throw new ParseException("Legal program '" + prog + "'followed by extra token " + t);
    prog.accept(CheckVisitor.INITIAL);
    return prog;
  }

  /** Parses an expression.
    *   Exp ::= if Exp then Exp else Exp
    *         | let Def+ in Exp
    *         | map TypedIdList to Exp
    *         | { PropStatementList }
    *         | Term { Binop Exp }
    */
  private AST parseExp() {
    Token token = in.readToken();

    if (token == Lexer.IF) return parseIf();
    if (token == Lexer.LET) return parseLet();
    if (token == Lexer.MAP) return parseMap();

    if (token == LeftBrace.ONLY) {
      AST[] exps = parseExps(SemiColon.ONLY, RightBrace.ONLY);
      if (exps.length == 0) throw new ParseException("Illegal empty block");
      return new Block(exps);
    }

    AST exp = parseTerm(token);

    Token next = in.peek();
    while (next instanceof OpToken) {
      OpToken op = (OpToken) next;
      in.readToken();
      if (! (op.isBinOp())) error(next, "binary operator");
      AST newTerm = parseTerm(in.readToken());
      exp = new BinOpApp(op.toBinOp(), exp, newTerm);
      next = in.peek();
    }
    return exp;
  }

  /** Parses a term.
    *   Term ::= Unop Term
    *          | Factor { ( ExpList ) }
    *          | Prim ( ExpList )
    *          | Empty
    *          | Int | Bool
    */
  private AST parseTerm(Token token) {

    if (token instanceof OpToken) {
      OpToken op = (OpToken) token;
      if (! op.isUnOp()) error(op,"unary operator");
      return new UnOpApp(op.toUnOp(), parseTerm(in.readToken()));
    }

    // Typed empty: empty : Type
    if (token == EmptyConstant.ONLY) {
      Token colon = in.readToken();
      if (!(colon instanceof Colon)) error(colon, "':' after 'empty'");
      Type type = parseType();
      return new TypedEmpty(type);
    }

    // Int and Bool constants
    if (token instanceof IntConstant) return (IntConstant) token;
    if (token instanceof BoolConstant) return (BoolConstant) token;

    // Valid Prim: must be followed by ( args )
    if (isValidPrim(token)) {
      Token next = in.readToken();
      if (next != LeftParen.ONLY) error(next, "'(' after primitive '" + token + "'");
      AST[] args = parseArgs();
      return new App((PrimFun) token, args);
    }

    // Eliminated primitives: error
    if (token instanceof PrimFun) {
      throw new ParseException("Primitive '" + token + "' is not supported in Typed Jam");
    }

    // Factor: Variable or (Exp), possibly followed by ( args )
    AST factor = parseFactor(token);
    Token next = in.peek();
    if (next == LeftParen.ONLY) {
      in.readToken();
      AST[] exps = parseArgs();
      return new App(factor, exps);
    }
    return factor;
  }

  /** Returns true if the token is a valid primitive in Typed Jam.
    * Prim ::= empty? | cons? | cons | first | rest */
  private boolean isValidPrim(Token t) {
    return t == EmptyPPrim.ONLY || t == ConsPPrim.ONLY ||
           t == ConsPrim.ONLY || t == FirstPrim.ONLY || t == RestPrim.ONLY;
  }

  /** Parses a factor: ( Exp ) | Id */
  private AST parseFactor(Token token) {
    if (token == LeftParen.ONLY) {
      AST exp = parseExp();
      token = in.readToken();
      if (token != RightParen.ONLY) error(token,"')'");
      return exp;
    }
    if (! (token instanceof Variable))
      error(token,"variable, constant, or '('");
    return (Term) token;
  }

  /** Parses 'if Exp then Exp else Exp' given that 'if' has already been read. */
  private AST parseIf() {
    AST test = parseExp();
    Token key1 = in.readToken();
    if (key1 != Lexer.THEN) error(key1,"'then'");
    AST conseq = parseExp();
    Token key2 = in.readToken();
    if (key2 != Lexer.ELSE) error(key2,"'else'");
    AST alt = parseExp();
    return new If(test,conseq,alt);
  }

  /** Parses 'let Def+ in Exp' given that 'let' has already been read. */
  private AST parseLet() {
    Def[] defs = parseDefs(false);
    AST body = parseExp();
    return new Let(defs,body);
  }

  /** Parses 'map TypedIdList to Exp' given that 'map' has already been read.
    * TypedIdList ::= { PropTypedIdList }
    * PropTypedIdList ::= TypedId | TypedId , PropTypedIdList
    * TypedId ::= Id : Type
    */
  private AST parseMap() {
    LinkedList<Variable> vars = new LinkedList<Variable>();
    LinkedList<Type> types = new LinkedList<Type>();
    Token t = in.readToken();
    if (t == Lexer.TO) {
      AST body = parseExp();
      return new Map(new Variable[0], new Type[0], body);
    }
    do {
      if (! (t instanceof Variable)) error(t,"variable");
      vars.addLast((Variable) t);
      Token colon = in.readToken();
      if (!(colon instanceof Colon)) error(colon, "':' in typed parameter");
      types.addLast(parseType());
      t = in.readToken();
      if (t == Lexer.TO) break;
      if (t != Comma.ONLY) error(t, "'to' or ','");
      t = in.readToken();
    } while (true);
    AST body = parseExp();
    return new Map(
      vars.toArray(new Variable[0]),
      types.toArray(new Type[0]),
      body
    );
  }

  /** Parses '<exp-list> <delim>' where
    *  <exp-list>      ::= <empty> | <prop-exp-list>
    *  <prop-exp-list> ::= <exp> | <exp> <separator> <prop-exp-list>
    */
  private AST[] parseExps(Token separator, Token delim) {
    LinkedList<AST> exps = new LinkedList<AST>();
    Token next = in.peek();

    if (next == delim) {
      in.readToken();
      return new AST[0];
    }

    do {
      AST exp = parseExp();
      exps.addLast(exp);
      next = in.readToken();
    } while (next == separator);

    if (next != delim) error(next,"'" + separator + "' or '" + delim + "'");
    return (AST[]) exps.toArray(new AST[0]);
  }

  private AST[] parseArgs() { return parseExps(Comma.ONLY,RightParen.ONLY); }

  /** Parses a proper list of typed definitions.
    *   Def ::= TypedId := Exp ;
    *   TypedId ::= Id : Type
    * Consumes 'in' following the definition list. */
  private Def[] parseDefs(boolean forceMap) {
    LinkedList<Def> defs = new LinkedList<Def>();
    Token t = in.readToken();

    do {
      Def d = parseDef(t);
      if (forceMap && (! (d.rhs() instanceof Map)))
        throw new ParseException("right hand side of definition '" + d + "' is not a map expression");
      defs.addLast(d);
      t = in.readToken();
    } while (t != Lexer.IN);

    return (Def[]) defs.toArray(new Def[0]);
  }

  /** Parses TypedId := Exp ; given that the first token (variable name) has been read. */
  private Def parseDef(Token var) {
    if (! (var instanceof Variable)) error(var, "variable");

    Token colon = in.readToken();
    if (!(colon instanceof Colon)) error(colon, "':' in typed definition");
    Type type = parseType();

    Token key = in.readToken();
    if (key != Lexer.BIND) error(key,"':='");

    AST exp = parseExp();

    Token semi = in.readToken();
    if (semi != SemiColon.ONLY) error(semi,"';'");
    return new Def((Variable) var, type, exp);
  }

  /** Parses a type expression.
    * Type ::= unit | int | bool | list Type | ref Type | (TypeList -> Type)
    * TypeList ::= { PropTypeList }
    * PropTypeList ::= Type | Type , PropTypeList
    */
  private Type parseType() {
    Token t = in.readToken();

    // Type keywords: int, bool, unit, list
    if (t == TypedLexer.INT_TYPE) return IntType.ONLY;
    if (t == TypedLexer.BOOL_TYPE) return BoolType.ONLY;
    if (t == TypedLexer.UNIT_TYPE) return UnitType.ONLY;
    if (t == TypedLexer.LIST_TYPE) return new ListType(parseType());

    // ref Type
    if (t == Lexer.REF) return new RefType(parseType());

    // (TypeList -> Type)
    if (t == LeftParen.ONLY) {
      LinkedList<Type> paramTypes = new LinkedList<Type>();
      // Check if type list is empty (-> immediately follows)
      if (in.peek() != Lexer.MINUS) {
        paramTypes.addLast(parseType());
        while (in.peek() == Comma.ONLY) {
          in.readToken(); // consume comma
          paramTypes.addLast(parseType());
        }
      }
      // Expect ->
      Token arrow1 = in.readToken();
      if (arrow1 != Lexer.MINUS) error(arrow1, "'->'");
      Token arrow2 = in.readToken();
      if (arrow2 != Lexer.GREATER_THAN) error(arrow2, "'>' in '->'");
      Type returnType = parseType();
      Token closeParen = in.readToken();
      if (closeParen != RightParen.ONLY) error(closeParen, "')'");
      return new FunType(paramTypes.toArray(new Type[0]), returnType);
    }

    error(t, "type");
    return null; // unreachable
  }

  private AST error(Token found, String expected) {
    throw new ParseException("Token '" + found + "' appears where " + expected + " was expected");
  }

  public static void main(String[] args) throws IOException {
    if (args.length == 0) return;
    Parser p = new Parser(args[0]);
    AST prog = p.parse();
  }
}

import junit.framework.TestCase;
import java.io.*;

/** Agent tests for Typed Jam - covers edge cases beyond public tests. */
public class Assign5AgentTest extends TestCase {

  public Assign5AgentTest(String name) { super(name); }

  private void eagerCheck(String name, String answer, String program) {
    Interpreter interp = new Interpreter(new StringReader(program));
    assertEquals("eager " + name, answer, interp.eagerEval().toString());
  }

  private void lazyCheck(String name, String answer, String program) {
    Interpreter interp = new Interpreter(new StringReader(program));
    assertEquals("lazy " + name, answer, interp.lazyEval().toString());
  }

  private void allCheck(String name, String answer, String program) {
    eagerCheck(name, answer, program);
    lazyCheck(name, answer, program);
  }

  // --- Basic arithmetic ---
  public void testSimpleAdd() {
    allCheck("simpleAdd", "5", "2 + 3");
  }

  public void testSimpleMul() {
    allCheck("simpleMul", "12", "3 * 4");
  }

  public void testNegation() {
    allCheck("negation", "-5", "- 5");
  }

  public void testBoolNot() {
    allCheck("boolNot", "false", "~ true");
  }

  // --- Type checking: correct programs ---
  public void testLetSimple() {
    allCheck("letSimple", "10",
        "let x: int := 5; in x + x");
  }

  public void testLetBool() {
    allCheck("letBool", "true",
        "let b: bool := true; in b & true");
  }

  public void testMapApply() {
    allCheck("mapApply", "7",
        "let f: (int -> int) := map x: int to x + 1; in f(6)");
  }

  public void testMapTwoArgs() {
    allCheck("mapTwoArgs", "15",
        "let add: (int, int -> int) := map x: int, y: int to x + y; in add(7, 8)");
  }

  public void testEmptyInt() {
    allCheck("emptyInt", "()", "empty: int");
  }

  public void testConsList() {
    allCheck("consList", "(1 2 3)",
        "cons(1, cons(2, cons(3, empty: int)))");
  }

  public void testFirstCons() {
    allCheck("firstCons", "42",
        "first(cons(42, empty: int))");
  }

  public void testRestCons() {
    allCheck("restCons", "(2 3)",
        "rest(cons(1, cons(2, cons(3, empty: int))))");
  }

  public void testEmptyPred() {
    allCheck("emptyPred", "true",
        "empty?(empty: int)");
  }

  public void testConsPred() {
    allCheck("consPred", "true",
        "cons?(cons(1, empty: int))");
  }

  public void testEmptyPredFalse() {
    allCheck("emptyPredFalse", "false",
        "empty?(cons(1, empty: int))");
  }

  // --- If-then-else ---
  public void testIfTrue() {
    allCheck("ifTrue", "1", "if true then 1 else 2");
  }

  public void testIfFalse() {
    allCheck("ifFalse", "2", "if false then 1 else 2");
  }

  // --- Ref cells ---
  public void testRefBasic() {
    allCheck("refBasic", "5",
        "let r: ref int := ref 5; in !r");
  }

  public void testRefAssign() {
    allCheck("refAssign", "10",
        "let r: ref int := ref 5; in { r <- 10; !r }");
  }

  public void testRefAssignUnit() {
    allCheck("refAssignUnit", "unit",
        "let r: ref int := ref 5; in r <- 10");
  }

  // --- Blocks ---
  public void testBlockSingle() {
    allCheck("blockSingle", "42", "{42}");
  }

  public void testBlockMultiple() {
    allCheck("blockMultiple", "3", "{1; 2; 3}");
  }

  // --- Type errors ---
  public void testTypeErrorAddBool() {
    try {
      allCheck("typeErrorAddBool", "err", "1 + true");
      fail("Expected TypeException for 1 + true");
    } catch (TypeException e) { /* expected */ }
  }

  public void testTypeErrorIfNotBool() {
    try {
      allCheck("typeErrorIfNotBool", "err", "if 5 then 1 else 2");
      fail("Expected TypeException for if 5...");
    } catch (TypeException e) { /* expected */ }
  }

  public void testTypeErrorIfBranchMismatch() {
    try {
      allCheck("typeErrorIfMismatch", "err", "if true then 1 else true");
      fail("Expected TypeException for mismatched if branches");
    } catch (TypeException e) { /* expected */ }
  }

  public void testTypeErrorBangNonRef() {
    try {
      allCheck("typeErrorBangNonRef", "err", "! 5");
      fail("Expected TypeException for ! 5");
    } catch (TypeException e) { /* expected */ }
  }

  public void testTypeErrorGetsNonRef() {
    try {
      allCheck("typeErrorGetsNonRef", "err", "5 <- 3");
      fail("Expected TypeException for 5 <- 3");
    } catch (TypeException e) { /* expected */ }
  }

  public void testTypeErrorLetMismatch() {
    try {
      allCheck("typeErrorLetMismatch", "err",
          "let x: bool := 5; in x");
      fail("Expected TypeException for int assigned to bool");
    } catch (TypeException e) { /* expected */ }
  }

  public void testTypeErrorConsTypeMismatch() {
    try {
      allCheck("typeErrorConsMismatch", "err",
          "cons(true, cons(1, empty: int))");
      fail("Expected TypeException for cons type mismatch");
    } catch (TypeException e) { /* expected */ }
  }

  public void testTypeErrorFirstNonList() {
    try {
      allCheck("typeErrorFirstNonList", "err", "first(5)");
      fail("Expected TypeException for first(5)");
    } catch (TypeException e) { /* expected */ }
  }

  public void testTypeErrorEqualsMismatch() {
    try {
      allCheck("typeErrorEqualsMismatch", "err", "1 = true");
      fail("Expected TypeException for 1 = true");
    } catch (TypeException e) { /* expected */ }
  }

  public void testTypeErrorWrongArgCount() {
    try {
      allCheck("typeErrorWrongArgCount", "err",
          "let f: (int -> int) := map x: int to x; in f(1, 2)");
      fail("Expected TypeException for wrong arg count");
    } catch (TypeException e) { /* expected */ }
  }

  // --- Parse errors for eliminated prims ---
  public void testEliminatedArity() {
    try {
      allCheck("eliminatedArity", "err",
          "arity(map x: int to x)");
      fail("Expected ParseException for arity");
    } catch (ParseException e) { /* expected */ }
  }

  public void testEliminatedNumberP() {
    try {
      allCheck("eliminatedNumberP", "err", "number?(5)");
      fail("Expected ParseException for number?");
    } catch (ParseException e) { /* expected */ }
  }

  public void testEliminatedFunctionP() {
    try {
      allCheck("eliminatedFunctionP", "err",
          "function?(map x: int to x)");
      fail("Expected ParseException for function?");
    } catch (ParseException e) { /* expected */ }
  }

  public void testEliminatedListP() {
    try {
      allCheck("eliminatedListP", "err", "list?(empty: int)");
      fail("Expected ParseException for list?");
    } catch (ParseException e) { /* expected */ }
  }

  public void testEliminatedRefP() {
    try {
      allCheck("eliminatedRefP", "err", "ref?(ref 5)");
      fail("Expected ParseException for ref?");
    } catch (ParseException e) { /* expected */ }
  }

  // --- Complex typed programs ---
  public void testRecursiveFunction() {
    allCheck("recursive", "120",
        "let fact: (int -> int) := map n: int to if n = 0 then 1 else n * fact(n - 1); in fact(5)");
  }

  public void testZeroArgMap() {
    allCheck("zeroArgMap", "42",
        "let f: ( -> int) := map to 42; in f()");
  }

  public void testHigherOrderFunction() {
    allCheck("higherOrder", "10",
        "let apply: ((int -> int), int -> int) := map f: (int -> int), x: int to f(x); " +
        "double: (int -> int) := map x: int to x * 2; in apply(double, 5)");
  }

  public void testNestedLet() {
    allCheck("nestedLet", "15",
        "let x: int := 5; in let y: int := x + 10; in y");
  }

  public void testListOfBools() {
    allCheck("listOfBools", "(true false)",
        "cons(true, cons(false, empty: bool))");
  }

  // --- Comparison operators ---
  public void testLessThan() {
    allCheck("lessThan", "true", "3 < 5");
  }

  public void testGreaterThan() {
    allCheck("greaterThan", "false", "3 > 5");
  }

  public void testEqualsInt() {
    allCheck("equalsInt", "true", "5 = 5");
  }

  public void testNotEquals() {
    allCheck("notEquals", "true", "3 != 5");
  }

  // --- Short-circuit boolean ---
  public void testAndShortCircuit() {
    allCheck("andShortCircuit", "false", "false & true");
  }

  public void testOrShortCircuit() {
    allCheck("orShortCircuit", "true", "true | false");
  }

  // --- Complex type annotations ---
  public void testRefList() {
    allCheck("refList", "(1 2)",
        "let r: ref list int := ref cons(1, cons(2, empty: int)); in !r");
  }

  public void testNestedListType() {
    allCheck("nestedListType", "((1 2) (3 4))",
        "let l1: list int := cons(1, cons(2, empty: int)); " +
        "l2: list int := cons(3, cons(4, empty: int)); " +
        "in cons(l1, cons(l2, empty: list int))");
  }
}

