+/** Type checker for Typed Jam (Assignment 5). */
+
+/** Exception class for type errors. */
+class TypeException extends RuntimeException {
+  TypeException(String msg) { super(msg); }
+}
+
+/** Type checker that walks the AST and verifies type consistency.
+  * Uses a type environment mapping variables to their declared types. */
+class TypeChecker {
+
+  /** Binding from Variable to Type for the type environment. */
+  static class TypeBinding implements WithVariable {
+    private Variable var;
+    private Type type;
+    TypeBinding(Variable v, Type t) { var = v; type = t; }
+    public Variable var() { return var; }
+    public Type type() { return type; }
+  }
+
+  /** The type environment. */
+  private PureList<TypeBinding> env;
+
+  /** Creates a TypeChecker with the given type environment. */
+  TypeChecker(PureList<TypeBinding> e) { env = e; }
+
+  /** Creates a TypeChecker with an empty environment. */
+  TypeChecker() { this(new Empty<TypeBinding>()); }
+
+  /** Type-checks the given AST and returns its type. Throws TypeException on error. */
+  Type check(AST ast) {
+    if (ast instanceof IntConstant) return IntType.ONLY;
+    if (ast instanceof BoolConstant) return BoolType.ONLY;
+    if (ast instanceof TypedEmpty) return new ListType(((TypedEmpty) ast).type());
+    if (ast instanceof EmptyConstant) throw new TypeException("Untyped empty constant");
+    if (ast instanceof Variable) return checkVariable((Variable) ast);
+    if (ast instanceof PrimFun) throw new TypeException("Primitive '" + ast + "' used as value");
+    if (ast instanceof UnOpApp) return checkUnOpApp((UnOpApp) ast);
+    if (ast instanceof BinOpApp) return checkBinOpApp((BinOpApp) ast);
+    if (ast instanceof App) return checkApp((App) ast);
+    if (ast instanceof Map) return checkMap((Map) ast);
+    if (ast instanceof If) return checkIf((If) ast);
+    if (ast instanceof Let) return checkLet((Let) ast);
+    if (ast instanceof Block) return checkBlock((Block) ast);
+    throw new TypeException("Unknown AST node: " + ast);
+  }
+
+  /** Looks up a variable in the type environment. */
+  private Type checkVariable(Variable v) {
+    TypeBinding match = env.accept(new LookupVisitor<TypeBinding>(v));
+    if (match == null) throw new TypeException("variable " + v + " is unbound");
+    return match.type();
+  }
+
+  /** Type-checks a unary operator application. */
+  private Type checkUnOpApp(UnOpApp u) {
+    Type argType = check(u.arg());
+    return u.rator().accept(new UnOpTypeChecker(argType));
+  }
+
+  /** Type-checks a binary operator application. */
+  private Type checkBinOpApp(BinOpApp b) {
+    Type arg1Type = check(b.arg1());
+    Type arg2Type = check(b.arg2());
+    return b.rator().accept(new BinOpTypeChecker(arg1Type, arg2Type));
+  }
+
+  /** Type-checks a function application (including primitive applications). */
+  private Type checkApp(App a) {
+    AST rator = a.rator();
+    AST[] args = a.args();
+
+    // Handle primitive function applications
+    if (rator instanceof PrimFun) {
+      return checkPrimApp((PrimFun) rator, args);
+    }
+
+    // Handle user-defined function applications
+    Type ratorType = check(rator);
+    if (!(ratorType instanceof FunType)) {
+      throw new TypeException(rator + " has type " + ratorType + " which is not a function type");
+    }
+    FunType funType = (FunType) ratorType;
+    Type[] paramTypes = funType.paramTypes();
+    if (paramTypes.length != args.length) {
+      throw new TypeException("Function expects " + paramTypes.length + " arguments but got " + args.length);
+    }
+    for (int i = 0; i < args.length; i++) {
+      Type argType = check(args[i]);
+      if (!argType.equals(paramTypes[i])) {
+        throw new TypeException("Argument " + (i + 1) + " has type " + argType +
+            " but " + paramTypes[i] + " expected");
+      }
+    }
+    return funType.returnType();
+  }
+
+  /** Type-checks a primitive function application.
+    * Handles polymorphic primitives (cons, first, rest, empty?, cons?). */
+  private Type checkPrimApp(PrimFun pf, AST[] args) {
+
+    // cons : 'a, list 'a -> list 'a
+    if (pf instanceof ConsPrim) {
+      if (args.length != 2) throw new TypeException("cons requires 2 arguments");
+      Type firstType = check(args[0]);
+      Type restType = check(args[1]);
+      if (!(restType instanceof ListType)) {
+        throw new TypeException("Second argument to cons must be a list, got " + restType);
+      }
+      Type elemType = ((ListType) restType).elemType();
+      if (!firstType.equals(elemType)) {
+        throw new TypeException("First argument to cons has type " + firstType +
+            " but list element type is " + elemType);
+      }
+      return restType;
+    }
+
+    // first : list 'a -> 'a
+    if (pf instanceof FirstPrim) {
+      if (args.length != 1) throw new TypeException("first requires 1 argument");
+      Type argType = check(args[0]);
+      if (!(argType instanceof ListType)) {
+        throw new TypeException("Argument to first must be a list, got " + argType);
+      }
+      return ((ListType) argType).elemType();
+    }
+
+    // rest : list 'a -> list 'a
+    if (pf instanceof RestPrim) {
+      if (args.length != 1) throw new TypeException("rest requires 1 argument");
+      Type argType = check(args[0]);
+      if (!(argType instanceof ListType)) {
+        throw new TypeException("Argument to rest must be a list, got " + argType);
+      }
+      return argType;
+    }
+
+    // empty? : list 'a -> bool
+    if (pf instanceof EmptyPPrim) {
+      if (args.length != 1) throw new TypeException("empty? requires 1 argument");
+      Type argType = check(args[0]);
+      if (!(argType instanceof ListType)) {
+        throw new TypeException("Argument to empty? must be a list, got " + argType);
+      }
+      return BoolType.ONLY;
+    }
+
+    // cons? : list 'a -> bool
+    if (pf instanceof ConsPPrim) {
+      if (args.length != 1) throw new TypeException("cons? requires 1 argument");
+      Type argType = check(args[0]);
+      if (!(argType instanceof ListType)) {
+        throw new TypeException("Argument to cons? must be a list, got " + argType);
+      }
+      return BoolType.ONLY;
+    }
+
+    throw new TypeException("Unsupported primitive: " + pf);
+  }
+
+  /** Type-checks a map (lambda) expression. Returns a FunType. */
+  private Type checkMap(Map m) {
+    Variable[] vars = m.vars();
+    Type[] types = m.types();
+    PureList<TypeBinding> newEnv = env;
+    for (int i = vars.length - 1; i >= 0; i--) {
+      newEnv = newEnv.cons(new TypeBinding(vars[i], types[i]));
+    }
+    TypeChecker newTC = new TypeChecker(newEnv);
+    Type bodyType = newTC.check(m.body());
+    return new FunType(types.clone(), bodyType);
+  }
+
+  /** Type-checks an if-then-else expression. */
+  private Type checkIf(If i) {
+    Type testType = check(i.test());
+    if (!testType.equals(BoolType.ONLY)) {
+      throw new TypeException("If test must be bool, got " + testType);
+    }
+    Type conseqType = check(i.conseq());
+    Type altType = check(i.alt());
+    if (!conseqType.equals(altType)) {
+      throw new TypeException("If branches have different types: " + conseqType + " and " + altType);
+    }
+    return conseqType;
+  }
+
+  /** Type-checks a let expression with recursive definitions. */
+  private Type checkLet(Let l) {
+    Def[] defs = l.defs();
+    Variable[] vars = l.vars();
+
+    // Build extended environment with declared types (for recursive defs)
+    PureList<TypeBinding> newEnv = env;
+    for (int i = vars.length - 1; i >= 0; i--) {
+      newEnv = newEnv.cons(new TypeBinding(vars[i], defs[i].type()));
+    }
+    TypeChecker newTC = new TypeChecker(newEnv);
+
+    // Check each RHS type matches declared type
+    for (int i = 0; i < defs.length; i++) {
+      Type rhsType = newTC.check(defs[i].rhs());
+      if (!rhsType.equals(defs[i].type())) {
+        throw new TypeException("Definition of " + vars[i] + " declared type " +
+            defs[i].type() + " but RHS has type " + rhsType);
+      }
+    }
+    return newTC.check(l.body());
+  }
+
+  /** Type-checks a block expression. Returns the type of the last expression. */
+  private Type checkBlock(Block b) {
+    AST[] exps = b.exps();
+    Type result = null;
+    for (AST exp : exps) {
+      result = check(exp);
+    }
+    return result;
+  }
+
+  /** Visitor for type-checking unary operators. */
+  class UnOpTypeChecker implements UnOpVisitor<Type> {
+    private Type argType;
+    UnOpTypeChecker(Type t) { argType = t; }
+
+    public Type forUnOpPlus() {
+      if (!argType.equals(IntType.ONLY))
+        throw new TypeException("Unary '+' requires int, got " + argType);
+      return IntType.ONLY;
+    }
+    public Type forUnOpMinus() {
+      if (!argType.equals(IntType.ONLY))
+        throw new TypeException("Unary '-' requires int, got " + argType);
+      return IntType.ONLY;
+    }
+    public Type forOpTilde() {
+      if (!argType.equals(BoolType.ONLY))
+        throw new TypeException("'~' requires bool, got " + argType);
+      return BoolType.ONLY;
+    }
+    public Type forOpBang() {
+      if (!(argType instanceof RefType))
+        throw new TypeException("'!' requires ref type, got " + argType);
+      return ((RefType) argType).elemType();
+    }
+    public Type forOpRef() {
+      return new RefType(argType);
+    }
+  }
+
+  /** Visitor for type-checking binary operators. */
+  class BinOpTypeChecker implements BinOpVisitor<Type> {
+    private Type arg1Type, arg2Type;
+    BinOpTypeChecker(Type t1, Type t2) { arg1Type = t1; arg2Type = t2; }
+
+    private void requireBothInt(String op) {
+      if (!arg1Type.equals(IntType.ONLY))
+        throw new TypeException("'" + op + "' requires int, got " + arg1Type);
+      if (!arg2Type.equals(IntType.ONLY))
+        throw new TypeException("'" + op + "' requires int, got " + arg2Type);
+    }
+    private void requireBothBool(String op) {
+      if (!arg1Type.equals(BoolType.ONLY))
+        throw new TypeException("'" + op + "' requires bool, got " + arg1Type);
+      if (!arg2Type.equals(BoolType.ONLY))
+        throw new TypeException("'" + op + "' requires bool, got " + arg2Type);
+    }
+
+    public Type forBinOpPlus() { requireBothInt("+"); return IntType.ONLY; }
+    public Type forBinOpMinus() { requireBothInt("-"); return IntType.ONLY; }
+    public Type forOpTimes() { requireBothInt("*"); return IntType.ONLY; }
+    public Type forOpDivide() { requireBothInt("/"); return IntType.ONLY; }
+    public Type forOpLessThan() { requireBothInt("<"); return BoolType.ONLY; }
+    public Type forOpGreaterThan() { requireBothInt(">"); return BoolType.ONLY; }
+    public Type forOpLessThanEquals() { requireBothInt("<="); return BoolType.ONLY; }
+    public Type forOpGreaterThanEquals() { requireBothInt(">="); return BoolType.ONLY; }
+    public Type forOpAnd() { requireBothBool("&"); return BoolType.ONLY; }
+    public Type forOpOr() { requireBothBool("|"); return BoolType.ONLY; }
+
+    public Type forOpEquals() {
+      if (!arg1Type.equals(arg2Type))
+        throw new TypeException("'=' requires same types, got " + arg1Type + " and " + arg2Type);
+      return BoolType.ONLY;
+    }
+    public Type forOpNotEquals() {
+      if (!arg1Type.equals(arg2Type))
+        throw new TypeException("'!=' requires same types, got " + arg1Type + " and " + arg2Type);
+      return BoolType.ONLY;
+    }
+    public Type forOpGets() {
+      if (!(arg1Type instanceof RefType))
+        throw new TypeException("'<-' left side must be ref type, got " + arg1Type);
+      Type elemType = ((RefType) arg1Type).elemType();
+      if (!arg2Type.equals(elemType))
+        throw new TypeException("'<-' right side has type " + arg2Type +
+            " but ref element type is " + elemType);
+      return UnitType.ONLY;
+    }
+  }
+}
